function stripFence(s) {
  return String(s || '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
}

function safeParse(s) {
  try {
    return JSON.parse(s);
  } catch {
    return null;
  }
}

function pickFirstNonEmpty(...vals) {
  for (const v of vals) {
    if (v === undefined || v === null) continue;
    if (typeof v === 'string' && v.trim() === '') continue;
    return v;
  }
  return null;
}

/**
 * 从混合文本中提取第一个完整 JSON 对象或数组
 * 支持：
 * 1. 前后有说明文字
 * 2. ```json fenced 内容
 * 3. 两个 JSON 连续拼接
 * 4. JSON 内部有字符串、转义字符
 */
function extractFirstJsonBlock(text) {
  const s = String(text || '').trim();
  if (!s) return '';

  let start = -1;
  const stack = [];
  let inString = false;
  let escaped = false;

  for (let i = 0; i < s.length; i++) {
    const ch = s[i];

    if (escaped) {
      escaped = false;
      continue;
    }

    if (ch === '\\') {
      escaped = true;
      continue;
    }

    if (ch === '"') {
      inString = !inString;
      continue;
    }

    if (inString) continue;

    if (start === -1) {
      if (ch === '{' || ch === '[') {
        start = i;
        stack.push(ch);
      }
      continue;
    }

    if (ch === '{' || ch === '[') {
      stack.push(ch);
    } else if (ch === '}' || ch === ']') {
      const last = stack[stack.length - 1];
      if (
        (last === '{' && ch === '}') ||
        (last === '[' && ch === ']')
      ) {
        stack.pop();
        if (stack.length === 0) {
          return s.slice(start, i + 1);
        }
      }
    }
  }

  return '';
}

/**
 * 尝试从对象里找到真正的原始输出
 * 兼容常见字段名
 */
function getRawOutput(j) {
  return pickFirstNonEmpty(
    j.output,
    j.content,
    j.text,
    j.result,
    j.response,
    j.message,
    j.data,
    j.body
  );
}

/**
 * 尝试把任意输入解析成对象
 */
function parsePossiblyDirtyJson(raw) {
  if (raw && typeof raw === 'object' && !Array.isArray(raw)) {
    return { parsed: raw, method: 'raw_object' };
  }

  let s = String(raw || '').trim();
  if (!s) return { parsed: null, method: 'empty' };

  s = stripFence(s);

  // 1) 先直接 parse
  let parsed = safeParse(s);
  if (parsed && typeof parsed === 'object') {
    return { parsed, method: 'direct_parse' };
  }

  // 2) 提取第一个 JSON 块
  const firstJson = extractFirstJsonBlock(s);
  if (firstJson) {
    parsed = safeParse(firstJson);
    if (parsed && typeof parsed === 'object') {
      return { parsed, method: 'extract_first_json_block' };
    }
  }

  return { parsed: null, method: 'failed' };
}

const input = $input.first().json || {};
const raw = getRawOutput(input);

if (raw === null || raw === undefined || raw === '') {
  return [{
    json: {
      ...input,
      parse_ok: false,
      parse_method: 'missing_output',
      parse_error: '缺少可用输出字段（未找到 output/content/text/result/response/message/data/body）',
      raw_output: null,
      raw_output_preview: ''
    }
  }];
}

const parsedResult = parsePossiblyDirtyJson(raw);
const obj = parsedResult.parsed;

if (!obj || typeof obj !== 'object') {
  return [{
    json: {
      ...input,
      parse_ok: false,
      parse_method: parsedResult.method,
      parse_error: '内容梳理输出不是合法 JSON',
      raw_output: String(raw),
      raw_output_preview: String(raw).slice(0, 3000)
    }
  }];
}

return [{
  json: {
    ...input,
    parse_ok: true,
    parse_method: parsedResult.method,
    parse_error: '',
    raw_output: String(raw),
    raw_output_preview: String(raw).slice(0, 3000),
    parsed_output: obj
  }
}];

const uploadItems = $input.all();
const preparedItems = $('准备上传参数').all();

return uploadItems.map((item, idx) => {
  const resp = item.json || {};
  const prepared = preparedItems[idx]?.json || {};

  const publicUrl = resp.url || resp.publicUrl || prepared.publicUrl || '';

  return {
    json: {
      ...prepared,
      ...resp,
      publicUrl
    }
  };
});

const items = $input.all();

function pickFirst(...vals) {
  for (const v of vals) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return '';
}

function normalizeBase64(v) {
  const s = String(v || '').trim();
  if (!s) return '';
  const m = s.match(/^data:[^;]+;base64,(.+)$/);
  return m ? m[1] : s;
}

function safeNodeItems(nodeName) {
  try {
    return $(nodeName).all();
  } catch {
    return [];
  }
}

const inputItems = safeNodeItems('标准化输入');

return items.map((item, idx) => {
  const j = item.json || {};

  // 尽量按索引取对应的“标准化输入”数据；取不到再退回第一条
  const inputNode = inputItems[idx]?.json || inputItems[0]?.json || {};
  const imagePayload = j.image_payload || {};

  const taskId = pickFirst(
    j.task_id,
    j.taskId,
    inputNode.task_id,
    inputNode.taskId
  );

  const rawBase64 = pickFirst(
    imagePayload.base64,
    j.base64
  );
  const base64 = normalizeBase64(rawBase64);

  const mimeType = pickFirst(
    j.mimeType,
    imagePayload.mimeType,
    'image/png'
  );

  const imageIndex = Number(
    pickFirst(
      j.image_index,
      idx
    ) || 0
  );

  const fileName = pickFirst(
    j.fileName,
    imagePayload.fileName,
    `image_${imageIndex}.png`
  );

  const supabaseUrl = String(
    pickFirst(
      j.supabase_url,
      j.supabaseUrl,
      inputNode.supabase_url,
      inputNode.supabaseUrl
    )
  ).trim().replace(/\/+$/, '');

  const supabaseApiKey = String(
    pickFirst(
      j.supabase_api_key,
      j.supabaseApiKey,
      inputNode.supabase_api_key,
      inputNode.supabaseApiKey
    )
  ).trim();

  const supabaseBucket = String(
    pickFirst(
      j.supabase_bucket,
      j.supabaseBucket,
      inputNode.supabase_bucket,
      inputNode.supabaseBucket,
      'uploads'
    )
  ).trim();

  if (!taskId) {
    throw new Error(`item ${idx}: task_id is required for upload`);
  }
  if (!base64) {
    throw new Error(`item ${idx}: No base64 image data to upload`);
  }
  if (!supabaseUrl) {
    throw new Error(`item ${idx}: supabase_url not provided`);
  }
  if (!supabaseApiKey) {
    throw new Error(`item ${idx}: supabase_api_key not provided`);
  }
  if (!supabaseBucket) {
    throw new Error(`item ${idx}: supabase_bucket not provided`);
  }

  const uploadPath = `${taskId}/${fileName}`;
  const uploadUrl = `${supabaseUrl}/storage/v1/object/${supabaseBucket}/${uploadPath}`;
  const publicUrl = `${supabaseUrl}/storage/v1/object/public/${supabaseBucket}/${uploadPath}`;

  return {
    json: {
      ...j,
      task_id: taskId,
      base64,
      mimeType,
      fileName,
      image_index: imageIndex,
      supabase_url: supabaseUrl,
      supabase_api_key: supabaseApiKey,
      supabase_bucket: supabaseBucket,
      uploadPath,
      uploadUrl,
      publicUrl
    }
  };
});

const items = $input.all();
if (!items.length) {
  throw new Error('没有可聚合的 OSS 图片结果');
}

const first = items[0].json || {};
const images = items
  .map(it => {
    const j = it.json || {};
    return {
      index: Number(j.image_index || 0) || 0,
      url: j.publicUrl || '',
      fileName: j.fileName || '',
      mimeType: j.mimeType || ''
    };
  })
  .filter(x => x.url)
  .sort((a, b) => a.index - b.index);

if (!images.length) {
  throw new Error('publicUrl 为空，无法生成图片 URL 数组');
}

return [{
  json: {
    ...first,
    generated_images_json: JSON.stringify(images),
    layout_result_json: JSON.stringify({
      content_plan: first.content_plan || {},
      image_plan: first.image_plan || {}
    })
  }
}];

function unwrapRoot(x) {
  if (x && typeof x === 'object' && x.body && typeof x.body === 'object') return x.body;
  return x;
}

function stripDataPrefix(b64) {
  return String(b64 || '').replace(/^data:.*;base64,/, '').trim();
}

function findInlineImageParts(root) {
  const candidates = root?.candidates;
  if (!Array.isArray(candidates) || !candidates.length) return [];

  const imgs = [];
  for (const c of candidates) {
    const parts = c?.content?.parts;
    if (!Array.isArray(parts)) continue;

    for (const p of parts) {
      const inline = p?.inline_data || p?.inlineData;
      if (inline?.data) {
        imgs.push({
          b64: inline.data,
          mimeType: inline.mime_type || inline.mimeType || 'image/png'
        });
      }
    }
  }
  return imgs;
}

const items = $input.all();
const output = [];

for (let itemIndex = 0; itemIndex < items.length; itemIndex++) {
  const raw = items[itemIndex].json || {};
  const root = unwrapRoot(raw);
  const imgs = findInlineImageParts(root);

  if (!imgs.length) continue;

  for (let i = 0; i < imgs.length; i++) {
    const img = imgs[i];
    const mimeType = img.mimeType || 'image/png';
    const ext = /jpe?g/i.test(mimeType) ? 'jpg' : 'png';
    const b64 = stripDataPrefix(img.b64);

    if (!b64) continue;

    const globalIndex = output.length + 1;
    const localIndex = i + 1;

    output.push({
      json: {
        ...raw,
        task_id: raw.task_id || raw.taskId || '',
        image_upload_url: raw.image_upload_url || '',
        admin_token: raw.admin_token || '',
        image_index: globalIndex,
        image_payload: {
          global_index: globalIndex,
          local_index: localIndex,
          source_item_index: itemIndex + 1,
          mimeType,
          fileName: `knowledge_card_${globalIndex}.${ext}`,
          base64: b64
        }
      }
    });
  }
}

if (!output.length) {
  throw new Error('没有在任何输入项中找到图片 base64');
}

return output;

function s(v) {
  return v == null ? '' : String(v);
}

function asArray(v) {
  return Array.isArray(v) ? v : (v == null ? [] : [v]);
}

const GLOBAL_STYLE_MODE = 'raw';

function safeJsonStringify(obj) {
  try {
    return JSON.stringify(obj, null, 2);
  } catch {
    return '{}';
  }
}

function normalizeContentBlock(block) {
  const b = block && typeof block === 'object' ? block : {};
  return {
    type: s(b.type || 'text').trim(),
    text: s(b.text).trim(),
    items: asArray(b.items).map(x => s(x).trim()).filter(Boolean),
  };
}

function normalizeBlocks(blocks) {
  return asArray(blocks)
    .map(normalizeContentBlock)
    .filter(b => b.type || b.text || b.items.length);
}

function pickStyleSummary(styleObj) {
  const dna = styleObj?.style_dna || {};
  return {
    style_name: s(dna.style_name).trim(),
    one_sentence_definition: s(dna.one_sentence_definition).trim(),
  };
}

function extractUniversalPrompt(styleObj) {
  return s(
    styleObj?.generation_prompts?.prompt_text2img_universal ||
    styleObj?.generation_prompts?.prompt ||
    ''
  ).trim();
}

function extractNegativePrompt(styleObj) {
  return s(styleObj?.generation_prompts?.negative_prompt || '').trim();
}

function extractLayoutBlueprint(styleObj) {
  const lb = styleObj?.layout_blueprint;
  if (!lb || typeof lb !== 'object') return '';
  return safeJsonStringify(lb);
}

function extractContentMapping(styleObj) {
  const cm = styleObj?.content_mapping;
  if (!cm || typeof cm !== 'object') return '';
  return safeJsonStringify(cm);
}

function buildContentBlocksBlock(blocks) {
  const lines = [];
  lines.push('[CONTENT_BLOCKS]');

  for (const b of blocks) {
    lines.push(`type=${b.type || 'text'}`);
    if (b.text) lines.push(b.text);
    if (b.items.length) {
      for (const item of b.items) {
        lines.push(`- ${item}`);
      }
    }
    lines.push('');
  }

  lines.push('[/CONTENT_BLOCKS]');
  return lines.join('\n').trim();
}

function buildExactChineseTextBlock(blocks) {
  const lines = [];
  lines.push('[EXACT_CHINESE_TEXT]');

  for (const b of blocks) {
    if (b.text) lines.push(b.text);
    for (const item of b.items) {
      lines.push(item);
    }
  }

  lines.push('[/EXACT_CHINESE_TEXT]');
  return lines.join('\n');
}

function buildRawStyleBlock(styleObj) {
  if (!styleObj || typeof styleObj !== 'object') return '';

  const lines = [];
  const universalPrompt = extractUniversalPrompt(styleObj);
  const layoutBlueprint = extractLayoutBlueprint(styleObj);
  const contentMapping = extractContentMapping(styleObj);

  lines.push('[STYLE_JSON_PRIMARY_RULE]');
  lines.push('Use the reference style JSON as the primary visual instruction.');
  lines.push('Do NOT force a fixed knowledge-card layout unless the style JSON itself requires it.');
  lines.push('Do NOT rewrite the page into a default point+explain card.');
  lines.push('Follow the style JSON for composition, layout hierarchy, module style, visual density, and typography vibe.');
  lines.push('[/STYLE_JSON_PRIMARY_RULE]');

  if (universalPrompt) {
    lines.push('');
    lines.push('[STYLE_PROMPT_BASE]');
    lines.push(universalPrompt);
    lines.push('[/STYLE_PROMPT_BASE]');
  }

  if (layoutBlueprint) {
    lines.push('');
    lines.push('[LAYOUT_BLUEPRINT]');
    lines.push(layoutBlueprint);
    lines.push('[/LAYOUT_BLUEPRINT]');
  }

  if (contentMapping) {
    lines.push('');
    lines.push('[CONTENT_MAPPING]');
    lines.push(contentMapping);
    lines.push('[/CONTENT_MAPPING]');
  }

  return lines.join('\n');
}

function buildSummaryStyleBlock(styleObj) {
  if (!styleObj || typeof styleObj !== 'object') return '';

  const st = pickStyleSummary(styleObj);
  const lines = [];
  lines.push('[STYLE_GUIDE]');
  if (st.style_name) lines.push(`style_name: ${st.style_name}`);
  if (st.one_sentence_definition) lines.push(`definition: ${st.one_sentence_definition}`);
  lines.push('[/STYLE_GUIDE]');
  return lines.join('\n');
}

function buildStyleBlock(styleMode, styleObj) {
  if (!styleObj || typeof styleObj !== 'object') return '';
  if (styleMode === 'off') return '';
  if (styleMode === 'summary') return buildSummaryStyleBlock(styleObj);
  return buildRawStyleBlock(styleObj);
}

function buildTextRules() {
  return [
    'Render EXACT Chinese text only when Chinese text is provided.',
    'Do NOT change, paraphrase, translate, add, delete, or reorder Chinese text.',
    'Do NOT render English labels, template markers, JSON keys, XML tags, UI words, or structural placeholders.',
    'Forbidden text on image includes: TITLE, SUBTITLE, POINT, EXPLAIN, POINT_1, POINT_2, POINT_3, POINT_4, POINT_5, EXPLAIN_1, EXPLAIN_2, EXPLAIN_3, EXPLAIN_4, EXPLAIN_5.',
    'Text must be sharp, high-contrast, clean-edged, readable on mobile, with no blur and no broken strokes.',
    'Keep sufficient whitespace and avoid overlap.',
    'Do NOT force all pages into the same text layout.',
    'Use the provided content blocks as the page content source.'
  ].join(' ');
}

function buildPrompt({
  promptBase,
  blocks,
  styleBlock,
  layoutHint,
  purpose
}) {
  const base = s(promptBase).trim();

  const purposeLine = purpose ? `[PAGE_PURPOSE]\n${purpose}\n[/PAGE_PURPOSE]` : '';
  const layoutLine = layoutHint ? `[PAGE_LAYOUT_HINT]\n${layoutHint}\n[/PAGE_LAYOUT_HINT]` : '';
  const contentBlock = buildContentBlocksBlock(blocks);
  const exactChinese = buildExactChineseTextBlock(blocks);

  return [
    base,
    buildTextRules(),
    purposeLine,
    layoutLine,
    styleBlock,
    contentBlock,
    exactChinese
  ].filter(Boolean).join('\n\n');
}

function buildNegativePrompt(styleObj, userNeg) {
  const baseNeg = extractNegativePrompt(styleObj);
  const extraNeg = s(userNeg).trim();

  const hardNeg = [
    'English text',
    'English letters',
    'template markers',
    'JSON keys',
    'XML tags',
    'UI text',
    'watermark',
    'garbled text',
    'distorted characters',
    'wrong Chinese characters',
    'missing strokes',
    'cluttered layout',
    'overlapping text',
    'low resolution',
    'blurry text'
  ].join(', ');

  return [baseNeg, extraNeg, hardNeg].filter(Boolean).join(', ');
}

function buildRequestBody({ aspectRatio, promptText, negativePrompt }) {
  const ratioHintMap = {
    '3:4': 'portrait 3:4 layout',
    '4:5': 'portrait 4:5 layout',
    '1:1': 'square layout',
    '16:9': 'landscape 16:9 layout',
    '9:16': 'vertical 9:16 layout'
  };

  const ratioHint = ratioHintMap[aspectRatio] || `layout ratio ${aspectRatio}`;

  const finalPrompt = [
    promptText,
    '',
    '[LAYOUT_RATIO]',
    ratioHint,
    '[/LAYOUT_RATIO]',
    negativePrompt ? '' : null,
    negativePrompt ? '[NEGATIVE_PROMPT]' : null,
    negativePrompt || null,
    negativePrompt ? '[/NEGATIVE_PROMPT]' : null
  ].filter(v => v !== null && v !== '').join('\n');

  return {
    contents: [
      {
        role: 'user',
        parts: [
          {
            text: finalPrompt
          }
        ]
      }
    ],
    generationConfig: {
      responseModalities: ['IMAGE']
    }
  };
}

function hashForDedup(x) {
  const key = {
    blocks: x.content_blocks,
    aspect_ratio: x.aspect_ratio,
    layout_hint: x.layout_hint,
    purpose: x.purpose,
    style_name: x.style_summary?.style_name || ''
  };
  return JSON.stringify(key);
}

const items = $input.all();
if (!items.length) throw new Error('没有输入数据');

const normalized = items.map((it) => {
  const j = it.json || {};
  const aspect_ratio = s(j.aspect_ratio || '3:4').trim() || '3:4';
  const image_index = Number(j.image_index || j.index || 1) || 1;
  const layout_hint = s(j.layout_hint).trim();
  const purpose = s(j.purpose || 'section').trim();
  const content_blocks = normalizeBlocks(j.content_blocks);
  const style_mode = s(j.style_mode || GLOBAL_STYLE_MODE).trim() || GLOBAL_STYLE_MODE;
  const styleObj = (j.style_json_obj && typeof j.style_json_obj === 'object') ? j.style_json_obj : null;
  const styleBlock = buildStyleBlock(style_mode, styleObj);

  const promptText = buildPrompt({
    promptBase: j.prompt_base,
    blocks: content_blocks,
    styleBlock,
    layoutHint: layout_hint,
    purpose
  });

  const negativePrompt = buildNegativePrompt(styleObj, j.negative_prompt);
  const request_body = buildRequestBody({
    aspectRatio: aspect_ratio,
    promptText,
    negativePrompt
  });

  return {
    ...j,
    aspect_ratio,
    image_index,
    purpose,
    layout_hint,
    content_blocks,
    style_mode,
    style_summary: styleObj ? pickStyleSummary(styleObj) : null,
    request_body
  };
});

const seen = new Map();
const deduped = [];

for (const x of normalized) {
  const h = hashForDedup(x);
  if (!seen.has(h)) {
    seen.set(h, x.image_index);
    deduped.push(x);
  } else {
    const keptIndex = seen.get(h);
    if (x.image_index < keptIndex) {
      const idx = deduped.findIndex(d => hashForDedup(d) === h);
      if (idx >= 0) deduped[idx] = x;
      seen.set(h, x.image_index);
    }
  }
}

deduped.sort((a, b) => (a.image_index || 0) - (b.image_index || 0));
return deduped.map(x => ({ json: x }));

function s(v) {
  return v == null ? '' : String(v);
}

function asArray(v) {
  return Array.isArray(v) ? v : (v == null ? [] : [v]);
}

function normalizeContentBlock(block) {
  const b = block && typeof block === 'object' ? block : {};
  return {
    type: s(b.type || 'text').trim() || 'text',
    text: s(b.text).trim(),
    items: asArray(b.items).map(x => s(x).trim()).filter(Boolean),
  };
}

const items = $input.all();
const out = [];

for (const item of items) {
  const j = item.json || {};

  const imagePlan = j.image_plan && typeof j.image_plan === 'object' ? j.image_plan : {};
  const images = asArray(imagePlan.images);

  const aspect_ratio = s(imagePlan.aspect_ratio || j.aspect_ratio || '3:4').trim() || '3:4';
  const count = Math.max(1, Math.min(5, Number(imagePlan.count || images.length || j.image_count_user || 1) || 1));

  const style_json_obj =
    j.style_json_obj && typeof j.style_json_obj === 'object'
      ? j.style_json_obj
      : null;

  const style_mode = s(j.style_mode || (style_json_obj?.generation_prompts ? 'raw' : 'summary')).trim();

  const prompt_base =
    s(j.prompt_base).trim() ||
    s(style_json_obj?.generation_prompts?.prompt_text2img_universal).trim() ||
    s(style_json_obj?.generation_prompts?.prompt).trim();

  const commonBase = {
    ...j,
    aspect_ratio,
    image_count: count,
    style_mode,
    prompt_base,
    style_json_obj
  };

  for (let i = 0; i < images.length; i++) {
    const img = images[i] && typeof images[i] === 'object' ? images[i] : {};
    const index = Number(img.index || i + 1) || i + 1;

    const content_blocks = asArray(img.content_blocks)
      .map(normalizeContentBlock)
      .filter(b => b.text || b.items.length);

    if (!content_blocks.length) continue;

    out.push({
      json: {
        ...commonBase,
        image_index: index,
        index,
        purpose: s(img.purpose || (index === 1 ? 'cover' : 'section')).trim() || 'section',
        layout_type: s(img.layout_type || 'auto').trim() || 'auto',
        layout_hint: s(img.layout_hint).trim(),
        prompt_override: s(img.prompt).trim(),
        negative_prompt_override: s(img.negative_prompt).trim(),
        content_blocks
      }
    });
  }
}

out.sort((a, b) => {
  const ia = Number(a.json.image_index || 0) || 0;
  const ib = Number(b.json.image_index || 0) || 0;
  return ia - ib;
});

return out;

