  return v == null ? '' : String(v);
}

function normalizeContentBlock(block) {
  const b = block && typeof block === 'object' ? block : {};

  const type = s(b.type || 'text').trim() || 'text';
  const text = s(b.text).trim();
  const items = asArray(b.items)
    .map(x => s(x).trim())
    .filter(Boolean);

  return { type, text, items };
}

function fallbackSplitTextToBlocks(title, text, imageCount) {
  const cleanTitle = s(title).trim();
  const raw = s(text).trim();

  const paragraphs = raw
    .split(/\n{2,}|\r\n{2,}/)
    .map(x => x.trim())
    .filter(Boolean);

  const count = Math.max(1, Math.min(5, Number(imageCount) || 1));

  if (!paragraphs.length) {
    return Array.from({ length: count }, (_, idx) => ({
      index: idx + 1,
      purpose: idx === 0 ? 'cover' : 'section',
      layout_type: 'auto',
      layout_hint: '',
      content_blocks: idx === 0
        ? [{ type: 'title', text: cleanTitle }]
        : [{ type: 'paragraph', text: cleanTitle || '内容页' }],
      prompt: '',
      negative_prompt: ''
    }));
  }

  const bucketSize = Math.ceil(paragraphs.length / count);
  const out = [];

  for (let i = 0; i < count; i++) {
    const chunk = paragraphs.slice(i * bucketSize, (i + 1) * bucketSize);

    const blocks = [];
    if (i === 0 && cleanTitle) {
      blocks.push({ type: 'title', text: cleanTitle });
    }

    for (const p of chunk) {
      blocks.push({ type: 'paragraph', text: p });
    }

    if (!blocks.length) {
      blocks.push({ type: 'paragraph', text: cleanTitle || '内容页' });
    }

    out.push({
      index: i + 1,
      purpose: i === 0 ? 'cover' : 'section',
      layout_type: 'auto',
      layout_hint: '',
      content_blocks: blocks,
      prompt: '',
      negative_prompt: ''
    });
  }

  return out;
}

function normalizeImage(image, indexFallback) {
  const o = image && typeof image === 'object' ? image : {};
  const index = Number(o.index ?? indexFallback ?? 1) || 1;
  const purpose = s(o.purpose || (index === 1 ? 'cover' : 'section')).trim() || 'section';
  const layout_type = s(o.layout_type || 'auto').trim() || 'auto';
  const layout_hint = s(o.layout_hint).trim();
  const prompt = s(o.prompt).trim();
  const negative_prompt = s(o.negative_prompt).trim();

  const content_blocks = asArray(o.content_blocks)
    .map(normalizeContentBlock)
    .filter(b => b.text || b.items.length);

  return {
    index,
    purpose,
    layout_type,
    layout_hint,
    content_blocks,
    prompt,
    negative_prompt
  };
}

