function toText(v) {
  if (v == null) return '';
  if (Array.isArray(v)) {
    return v.map(x => {
      if (x == null) return '';
      if (typeof x === 'string') return x;
      if (typeof x === 'number') return String(x);
      if (typeof x === 'object' && x.text) return String(x.text);
      return '';
    }).join('');
  }
  if (typeof v === 'object' && v.text) return String(v.text);
  return String(v);
}

function extractJsonObjects(s) {
  s = String(s || '');
  const objs = [];
  let start = -1, depth = 0, inStr = false, esc = false;
  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    if (inStr) {
      if (esc) esc = false;
      else if (ch === '\\') esc = true;
      else if (ch === '"') inStr = false;
      continue;
    } else {
      if (ch === '"') { inStr = true; continue; }
    }
    if (ch === '{') {
      if (depth === 0) start = i;
      depth++;
    } else if (ch === '}') {
      depth--;
      if (depth === 0 && start >= 0) {
        objs.push(s.slice(start, i + 1));
        start = -1;
      }
    }
  }
  return objs;
}

function pickBestStyle(parsedList) {
  const scored = parsedList.map(o => {
    const styleName = o?.style_dna?.style_name ? 2 : 0;
    const hasPrompt = o?.generation_prompts?.prompt_text2img_universal ? 2 : 0;
    const hasLayout = o?.layout_blueprint?.modules ? 1 : 0;
    return { o, score: styleName + hasPrompt + hasLayout };
  }).sort((a,b) => b.score - a.score);
  return scored[0]?.o || null;
}

